"use strict";(globalThis.webpackChunkmy_website=globalThis.webpackChunkmy_website||[]).push([[613],{9877(e,o,t){t.r(o),t.d(o,{assets:()=>h,contentTitle:()=>r,default:()=>c,frontMatter:()=>a,metadata:()=>n,toc:()=>d});const n=JSON.parse('{"id":"stoicism/epictetus/discourses/book-2/discourses-book-2-chapter-1","title":"Discourses \u2014 Book 2, Chapter 1","description":"Book 2 \u2014 Chapter 1","source":"@site/docs/stoicism/epictetus/discourses/book-2/discourses-book-2-chapter-1.md","sourceDirName":"stoicism/epictetus/discourses/book-2","slug":"/stoicism/epictetus/discourses/book-2/discourses-book-2-chapter-1","permalink":"/justinus/docs/stoicism/epictetus/discourses/book-2/discourses-book-2-chapter-1","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":2,"frontMatter":{"sidebar_position":2,"title":"Discourses \u2014 Book 2, Chapter 1","sidebar_label":"Book 2, Ch. 1"},"sidebar":"philosophersSidebar","previous":{"title":"Discourses \u2014 Book 2","permalink":"/justinus/docs/stoicism/epictetus/discourses/book-2/"},"next":{"title":"Book 2, Ch. 2","permalink":"/justinus/docs/stoicism/epictetus/discourses/book-2/discourses-book-2-chapter-2"}}');var s=t(4848),i=t(8453);const a={sidebar_position:2,title:"Discourses \u2014 Book 2, Chapter 1",sidebar_label:"Book 2, Ch. 1"},r="Discourses",h={},d=[{value:"Book 2 \u2014 Chapter 1",id:"book-2--chapter-1",level:2},{value:"That There Is No Conflict Between Confidence And Caution",id:"that-there-is-no-conflict-between-confidence-and-caution",level:3},{value:"Sonnet 4.6 Summary",id:"sonnet-46-summary",level:2},{value:"Text",id:"text",level:2}];function l(e){const o={em:"em",h1:"h1",h2:"h2",h3:"h3",header:"header",p:"p",...(0,i.R)(),...e.components},{Details:t}=o;return t||function(e,o){throw new Error("Expected "+(o?"component":"object")+" `"+e+"` to be defined: you likely forgot to import, pass, or provide it.")}("Details",!0),(0,s.jsxs)(s.Fragment,{children:[(0,s.jsxs)("div",{style:{textAlign:"center"},children:[(0,s.jsx)(o.header,{children:(0,s.jsx)(o.h1,{id:"discourses",children:"Discourses"})}),(0,s.jsx)(o.h2,{id:"book-2--chapter-1",children:"Book 2 \u2014 Chapter 1"}),(0,s.jsx)(o.h3,{id:"that-there-is-no-conflict-between-confidence-and-caution",children:"That There Is No Conflict Between Confidence And Caution"})]}),"\n",(0,s.jsx)(o.p,{children:(0,s.jsx)(o.em,{children:"Translated by P.E. Matheson (Oxford: Clarendon Press, 1916)"})}),"\n",(0,s.jsxs)(t,{open:!0,children:[(0,s.jsx)("summary",{children:"Sonnet 4.6 Summary"}),(0,s.jsx)(o.h2,{id:"sonnet-46-summary",children:"Sonnet 4.6 Summary"}),(0,s.jsx)(o.p,{children:"The apparent paradox \u2014 be confident and cautious simultaneously \u2014 dissolves once you sort what each applies to. Caution belongs to the will, where real good and evil reside and where error is genuinely possible. Confidence belongs to everything outside the will, where nothing that happens to you can constitute real harm. The two don't conflict because they operate in different domains."}),(0,s.jsx)(o.p,{children:"The deer analogy captures how we actually behave: we flee the feathers (externals like death, pain, exile) and run straight into the nets (recklessness about our own character). We're bold where we should be careful and terrified where we should be calm \u2014 the exact inversion of wisdom."}),(0,s.jsx)(o.p,{children:"The closing reframes freedom: not the legal act of manumission, but the educated condition of a person who no longer has masters. The man who just freed his slave before the praetor may himself be enslaved to money, a lover, or a tyrant's favor. True freedom comes only from knowing what to approach with confidence and what with caution \u2014 and practicing it."})]}),"\n",(0,s.jsxs)(t,{open:!0,children:[(0,s.jsx)("summary",{children:"Text"}),(0,s.jsx)(o.h2,{id:"text",children:"Text"}),(0,s.jsx)(o.p,{children:"PERHAPS the contention of philosophers that it is possible in everything we do to combine confidence with caution may appear a paradox, but nevertheless we must do our best to consider whether it is true. In a sense, no doubt, caution seems to be contrary to confidence, and contraries are by no means compatible. But I think that what seems to many a paradox in this subject depends on a confusion, and it is this. If we really called upon a man to use caution and confidence in regard to the same things, they might fairly find fault with us as uniting qualities which cannot be united. But as a matter of fact there is nothing strange in the statement: for if it is true, as has often been said and often proved, that the true nature of good and also of evil depends on how we deal with impressions, and if things outside the will's control cannot be described as good or bad, we cannot surely call it a paradoxical demand of the philosophers if they say, 'Be confident in all that lies beyond the will's control, be cautious in all that is dependent on the will.' For if evil depends on evil choice, it is only in regard to matters of will that it is right to use caution; and if things outside the will's control, which do not depend on us, concern us in no way, we should use confidence in regard to these. And in that way we shall be at once cautious and confident and indeed confident because of our caution. For because we are cautious as to things which are really evil we shall get confidence to face things which are not so."}),(0,s.jsx)(o.p,{children:"However, we behave like deer: when hinds fear the feathers  and fly from them, where do they turn, and in what do they take refuge as a safe retreat? They turn to the nets, and so they perish because they confuse objects of fear with objects of confidence."}),(0,s.jsx)(o.p,{children:"So it is with us. Where do we show fear? In regard to things outside our will's control. Again, when do we behave with confidence as though there were nothing to fear? In matters within the will's control. So if only we are successful in things beyond our will's control we think it is of no consequence to us to be deceived or to act rashly, or to do a shameless deed, or to conceive a shameful desire. But where death or exile or pain or infamy confronts us, there we show the spirit of retreat and of wild alarm. Wherefore, as is likely with men who are mistaken in the"}),(0,s.jsx)(o.p,{children:"greatest matters, we convert our natural confidence into something bold, desperate, reckless, shameless, whereas we change our natural caution and modesty into a cowardly and abject quality, full of fears and perturbations. For if a man transfers his caution to the region of the will and the operations of the will, with the will to be cautious he will find that the will to avoid lies in his control: while if he turns his caution to what is beyond the control of our will, inasmuch as his will to avoid will be directed to what depends upon others he will of necessity be subject to fear, inconstancy, and perturbation. For it is not death or pain which is a fearful thing, but the fear of pain or death. Therefore men praise him who said"}),(0,s.jsx)(o.p,{children:"Not death, but shameful death, is to be feared."}),(0,s.jsx)(o.p,{children:"[Author unknown]"}),(0,s.jsx)(o.p,{children:"We ought then to turn our confidence towards death, and our caution towards the fear of death: what we really do is just the contrary; we fly from death, yet we pay no heed to forming judgements about death, but are reckless and indifferent. Socrates called such fears 'bogies', and rightly too. [Plato, Phaedo, 77e] For just as masks seem fearful and terrible to children from want of experience, so we are affected by events for much the same reason as children are affected by 'bogies'. For what makes a child? Want of knowledge. What makes a child? Want of instruction. For so far as a child knows those things he is no worse off than we are. What is death? A bogy. Turn it round and see what it is: you see it does not bite. The stuff of the body was bound to be parted from the airy element, either now or hereafter, as it existed apart from it before. Why then are you vexed if they are parted now? For if not parted now, they will be hereafter. Why so? That the revolution of the universe may be accomplished, for it has need of things present, things future, and things past and done with. What is pain? A bogy. Turn it round and see what it is. The poor flesh is subject to rough movement, then again to smooth. If it is not to your profit, the door stands open: if it is to your profit, bear it. For in every event the door must stand open and then we have no trouble."}),(0,s.jsx)(o.p,{children:"What then is the fruit of these judgements? A fruit which must needs be most noble and most becoming to those who are truly being educated --a mind tranquil and fearless and free. For on these matters you must not trust the multitude, who say, 'Only the free may be educated', but rather the philosophers who say, 'Only the educated are free.'"}),(0,s.jsx)(o.p,{children:"'What do you mean by that?'"}),(0,s.jsx)(o.p,{children:"I mean this. What else is freedom but power to pass our life as we will?"}),(0,s.jsx)(o.p,{children:"'True.'"}),(0,s.jsx)(o.p,{children:"Tell me, fellow men, do you wish to live doing wrong?"}),(0,s.jsx)(o.p,{children:"'We do not.'"}),(0,s.jsx)(o.p,{children:"Is no one free who does wrong?"}),(0,s.jsx)(o.p,{children:"'No one.'"}),(0,s.jsx)(o.p,{children:"Do you wish to live in fear, in pain, in distress of mind?"}),(0,s.jsx)(o.p,{children:"'By no means.'"}),(0,s.jsx)(o.p,{children:"Well, no man who suffers fear or pain or distress of mind is free, but whoever is quit of fears and pains and distresses is by the self-same road quit of slavery. How then shall we go on believing you, dearest lawgivers?"}),(0,s.jsx)(o.p,{children:"Do we allow none but the free to get education?"}),(0,s.jsx)(o.p,{children:"Nay! philosophers say that we do not allow any to be free except those whose education is complete: that is, God does not allow it."}),(0,s.jsx)(o.p,{children:"'Well then, when a man turns his slave round before the praetor,  does he do nothing?'"}),(0,s.jsx)(o.p,{children:"He does something."}),(0,s.jsx)(o.p,{children:"'What?'"}),(0,s.jsx)(o.p,{children:"He turns his slave round before the praetor."}),(0,s.jsx)(o.p,{children:"'Nothing else?'"}),(0,s.jsx)(o.p,{children:"Yes, he is bound to pay the twentieth for him."}),(0,s.jsx)(o.p,{children:"'What follows? Has not the man to whom this is done gained freedom?'"}),(0,s.jsx)(o.p,{children:"No more than he has gained peace of mind. For do you who can confer this freedom own no master? Have you not a master in money, a girl lover or a boy lover, the tyrant, or a friend of the tyrant? If not, why do you tremble when you go away to face a crisis of this sort? Therefore I say many times over: What you must practise and have at command is to know what you ought to approach with confidence, and what with caution; all that is beyond the control of the will with confidence, and what is dependent on the will with caution."}),(0,s.jsx)(o.p,{children:"'But' (says my pupil), 'have I not recited to you? Do you not know what I am doing?'"}),(0,s.jsx)(o.p,{children:"What are you engaged on? Paltry phrases. Away with your paltry phrases: show me how you stand in regard to the will to get and the will to avoid: if you do not fail to get what you will, or fall into what you will to avoid. As for those paltry periods, if you have sense you will take them away somewhere or other and make away with them."}),(0,s.jsx)(o.p,{children:"'What do you mean? Did not Socrates write?'"}),(0,s.jsx)(o.p,{children:"Yes, who wrote so much as he? But under what conditions? He could not always have some one at hand examining his judgements or to be examined by him in turn, and therefore be examined and questioned himself and was always putting to trial some primary conception or other in a practical way. This is what a philosopher writes: but paltry"}),(0,s.jsx)(o.p,{children:"phrases and periods he leaves to others, to the stupid or the blessed, those whose peace of mind gives them leisure for study or those who can draw no logical conclusions because of their folly."}),(0,s.jsx)(o.p,{children:"To-day, when the crisis calls you, will you go off and display your recitation and harp on, 'How cleverly I compose dialogues'? Nay, fellow man, make this your object, 'Look how I fail not to get what I will. Look how I escape what I will to avoid. Let death come and you shall know; bring me pains, prison, dishonour, condemnation.' This is the true field of display for a young man come from school. Leave those other trifles to other men; let no one ever hear you say a word on them, do not tolerate any compliments upon them; assume the air of being no one and of knowing nothing. Show that you know this only, how not to fail and how not to fall. Let others practise law-suits, logical puzzles and syllogisms: let your study be how to suffer death, bondage, the rack, exile: let all this be done with confidence and trust in Him who has called you to face them, and judged you worthy of this place you hold, wherein at your appointed post you shall show what is the power of reason, the Governing Principle, when arrayed against forces which are outside the will. And, if you do this, that paradox will no longer seem impossible or paradoxical--that we must show caution and confidence at the same time, confidence in regard to things beyond the will, caution in things which depend on the will."})]})]})}function c(e={}){const{wrapper:o}={...(0,i.R)(),...e.components};return o?(0,s.jsx)(o,{...e,children:(0,s.jsx)(l,{...e})}):l(e)}},8453(e,o,t){t.d(o,{R:()=>a,x:()=>r});var n=t(6540);const s={},i=n.createContext(s);function a(e){const o=n.useContext(i);return n.useMemo(function(){return"function"==typeof e?e(o):{...o,...e}},[o,e])}function r(e){let o;return o=e.disableParentContext?"function"==typeof e.components?e.components(s):e.components||s:a(e.components),n.createElement(i.Provider,{value:o},e.children)}}}]);